import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Using StringBuilder to store user input dynamically
        StringBuilder builder = new StringBuilder();

        // Validate user input length before copying
        if (input.length() <= 10) {
            builder.append(input);
        } else {
            System.out.println("Input exceeds buffer size limit.");
            return;
        }

        System.out.println("Hello, " + builder.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
